const body = $json.body ?? $json;
const required = ['product_name','product_description','audience'];
const missing = required.filter(k => !body[k] || String(body[k]).trim() === '');
if (missing.length) {
  throw new Error(`Missing required fields: ${missing.join(', ')}`);
}

const run_id = body.request_id || `run_${Date.now()}`;
const dedup_key = `${body.product_name}::${body.audience}::${body.request_id || 'no_request_id'}`;

return [{
  json: {
    run_id,
    dedup_key,
    received_at: new Date().toISOString(),
    product_name: body.product_name,
    product_description: body.product_description,
    audience: body.audience,
    awareness_level: body.awareness_level || 'cold',
    pain_points: Array.isArray(body.pain_points) ? body.pain_points : [],
    mechanism: body.mechanism || 'specific mechanism not provided',
    guarantee: body.guarantee || 'satisfaction guarantee',
    compliance_note: 'Review claims for platform and legal compliance before launch.'
  }
}];

const d = $json;
const basePain = d.pain_points.length ? d.pain_points : [
  'current solutions feel inconvenient',
  'results feel inconsistent',
  'hard to know what actually works'
];

const hooks = [
  {
    hook_type: 'Pattern Interrupt',
    audio_hook: `Stop guessing with ${d.product_name}.`,
    visual_open: 'Quick close-up showing the exact before state/problem.',
    pain_targeted: basePain[0],
    objection_handled: 'I tried similar products before',
    why_it_works: 'Fast pattern break + specificity',
    risk: 'Low'
  },
  {
    hook_type: 'Us vs Them',
    audio_hook: `Most options mask it. ${d.product_name} targets the root.`,
    visual_open: 'Split-screen old method vs new method.',
    pain_targeted: basePain[1] || basePain[0],
    objection_handled: 'How is this different?',
    why_it_works: 'Clear contrast creates belief quickly',
    risk: 'Medium'
  },
  {
    hook_type: 'Proof First',
    audio_hook: 'Look closely — this is measurable progress.',
    visual_open: 'Zoomed proof visual with callout labels.',
    pain_targeted: basePain[2] || basePain[0],
    objection_handled: 'I need evidence',
    why_it_works: 'Evidence before claims lowers resistance',
    risk: 'Medium'
  }
];

return [{ json: { ...d, hooks } }];

const d = $json;
const selected = d.hooks[0];
const script = {
  hook: selected.audio_hook,
  agitation: `If you've tried other fixes but still struggle, it's usually because they only treat symptoms — not the root issue.`,
  mechanism: `${d.product_name} works differently: ${d.mechanism}.`,
  proof: `Show a concrete demo moment tied to ${d.audience} and a believable timeframe.`,
  cta: `Tap Shop Now to try ${d.product_name} with ${d.guarantee}.`
};

return [{ json: { ...d, selected_hook: selected, script } }];

const d = $json;
const scenes = [
  { section: '0:00-0:03', prompt: `${d.audience} facing the core problem, handheld UGC framing, vertical 9:16` },
  { section: '0:03-0:12', prompt: `show frustrating status-quo method failing in realistic bathroom setting, 9:16` },
  { section: '0:12-0:25', prompt: `introduce ${d.product_name} application close-up, clean lighting, texture detail, 9:16` },
  { section: '0:25-0:35', prompt: `proof-style shot with visual labels and believable progress framing, 9:16` },
  { section: '0:35-0:45', prompt: `confident result shot plus product and guarantee badge, 9:16` }
];

return [{ json: { ...d, scenes } }];

const d = $json;
return [{
  json: {
    status: 'ok',
    run_id: d.run_id,
    dedup_key: d.dedup_key,
    product_name: d.product_name,
    audience: d.audience,
    selected_hook: d.selected_hook,
    hooks: d.hooks,
    script: d.script,
    scenes: d.scenes,
    instructions: [
      'If this output quality is too generic, replace Generate Hooks + Build Script with an LLM node.',
      'Keep a datastore keyed by dedup_key to enforce idempotency across retries.',
      'Store all outputs to Sheets/Notion/Airtable before ad launch.'
    ],
    compliance_note: d.compliance_note
  }
}];
